import { describe, it, expect, beforeEach, vi } from 'vitest';
import {
  ErrorRecoveryService,
  ErrorType,
  CircuitState,
} from './errorRecoveryService';
import { ErrorCode } from '../constants/errorCodes';

describe('ErrorRecoveryService', () => {
  let service: ErrorRecoveryService;

  beforeEach(() => {
    service = new ErrorRecoveryService();
    vi.clearAllMocks();
  });

  describe('Error Classification', () => {
    it('should classify network errors as transient', () => {
      const error = new Error('ECONNREFUSED');
      const classification = service.classifyError(error);

      expect(classification.type).toBe(ErrorType.NETWORK);
      expect(classification.isRetryable).toBe(true);
      expect(classification.maxRetries).toBeGreaterThan(0);
    });

    it('should classify timeout errors as transient', () => {
      const error = new Error('Request timeout');
      const classification = service.classifyError(error);

      expect(classification.type).toBe(ErrorType.TIMEOUT);
      expect(classification.isRetryable).toBe(true);
    });

    it('should classify rate limit errors with longer delay', () => {
      const error = {
        message: 'Too many requests',
        statusCode: 429,
      };
      const classification = service.classifyError(error);

      expect(classification.type).toBe(ErrorType.RATE_LIMIT);
      expect(classification.isRetryable).toBe(true);
      expect(classification.suggestedDelay).toBeGreaterThan(10000);
    });

    it('should classify authentication errors as permanent', () => {
      const error = {
        code: ErrorCode.AUTH_INVALID_CREDENTIALS,
        statusCode: 401,
      };
      const classification = service.classifyError(error);

      expect(classification.type).toBe(ErrorType.AUTHENTICATION);
      expect(classification.isRetryable).toBe(false);
      expect(classification.maxRetries).toBe(0);
    });

    it('should classify validation errors as permanent', () => {
      const error = {
        code: ErrorCode.VALIDATION_ERROR,
        statusCode: 400,
      };
      const classification = service.classifyError(error);

      expect(classification.type).toBe(ErrorType.VALIDATION);
      expect(classification.isRetryable).toBe(false);
    });

    it('should classify 404 errors as permanent', () => {
      const error = {
        statusCode: 404,
      };
      const classification = service.classifyError(error);

      expect(classification.type).toBe(ErrorType.PERMANENT);
      expect(classification.isRetryable).toBe(false);
    });

    it('should classify 500 errors as transient', () => {
      const error = {
        statusCode: 500,
      };
      const classification = service.classifyError(error);

      expect(classification.type).toBe(ErrorType.TRANSIENT);
      expect(classification.isRetryable).toBe(true);
    });

    it('should classify database errors as transient', () => {
      const error = {
        code: ErrorCode.DATABASE_CONNECTION_ERROR,
      };
      const classification = service.classifyError(error);

      expect(classification.type).toBe(ErrorType.TRANSIENT);
      expect(classification.isRetryable).toBe(true);
    });

    it('should classify unknown errors cautiously', () => {
      const error = new Error('Unknown error');
      const classification = service.classifyError(error);

      expect(classification.type).toBe(ErrorType.UNKNOWN);
      expect(classification.isRetryable).toBe(true);
      expect(classification.maxRetries).toBeLessThanOrEqual(2);
    });
  });

  describe('Exponential Backoff', () => {
    it('should calculate exponential backoff correctly', () => {
      const delay0 = service.calculateRetryDelay(0);
      const delay1 = service.calculateRetryDelay(1);
      const delay2 = service.calculateRetryDelay(2);

      expect(delay1).toBeGreaterThan(delay0);
      expect(delay2).toBeGreaterThan(delay1);
    });

    it('should respect max delay', () => {
      const delay = service.calculateRetryDelay(10, {
        maxRetries: 10,
        initialDelay: 1000,
        maxDelay: 5000,
        backoffMultiplier: 2,
        jitterFactor: 0,
      });

      expect(delay).toBeLessThanOrEqual(5000);
    });

    it('should add jitter to prevent thundering herd', () => {
      const delays = Array.from({ length: 10 }, () =>
        service.calculateRetryDelay(1, {
          maxRetries: 3,
          initialDelay: 1000,
          maxDelay: 10000,
          backoffMultiplier: 2,
          jitterFactor: 0.2,
        })
      );

      // Check that delays are not all the same (jitter is working)
      const uniqueDelays = new Set(delays);
      expect(uniqueDelays.size).toBeGreaterThan(1);
    });

    it('should handle zero jitter', () => {
      const delay1 = service.calculateRetryDelay(1, {
        maxRetries: 3,
        initialDelay: 1000,
        maxDelay: 10000,
        backoffMultiplier: 2,
        jitterFactor: 0,
      });

      const delay2 = service.calculateRetryDelay(1, {
        maxRetries: 3,
        initialDelay: 1000,
        maxDelay: 10000,
        backoffMultiplier: 2,
        jitterFactor: 0,
      });

      expect(delay1).toBe(delay2);
    });
  });

  describe('Retry Logic', () => {
    it('should succeed on first attempt', async () => {
      const operation = vi.fn().mockResolvedValue('success');

      const result = await service.executeWithRetry(operation, {
        operationName: 'test-operation',
      });

      expect(result).toBe('success');
      expect(operation).toHaveBeenCalledTimes(1);
    });

    it('should retry on transient errors', async () => {
      const operation = vi
        .fn()
        .mockRejectedValueOnce(new Error('ECONNREFUSED'))
        .mockResolvedValue('success');

      const result = await service.executeWithRetry(operation, {
        operationName: 'test-operation',
        retryConfig: {
          maxRetries: 3,
          initialDelay: 10,
          maxDelay: 100,
          backoffMultiplier: 2,
          jitterFactor: 0,
        },
      });

      expect(result).toBe('success');
      expect(operation).toHaveBeenCalledTimes(2);
    });

    it('should not retry on permanent errors', async () => {
      const error = {
        code: ErrorCode.VALIDATION_ERROR,
        statusCode: 400,
      };
      const operation = vi.fn().mockRejectedValue(error);

      await expect(
        service.executeWithRetry(operation, {
          operationName: 'test-operation',
        })
      ).rejects.toEqual(error);

      expect(operation).toHaveBeenCalledTimes(1);
    });

    it('should exhaust retries and throw last error', async () => {
      const error = new Error('ECONNREFUSED');
      const operation = vi.fn().mockRejectedValue(error);

      await expect(
        service.executeWithRetry(operation, {
          operationName: 'test-operation',
          retryConfig: {
            maxRetries: 2,
            initialDelay: 10,
            maxDelay: 100,
            backoffMultiplier: 2,
            jitterFactor: 0,
          },
        })
      ).rejects.toThrow('ECONNREFUSED');

      expect(operation).toHaveBeenCalledTimes(3); // Initial + 2 retries
    });

    it('should call onRetry callback', async () => {
      const onRetry = vi.fn();
      const operation = vi
        .fn()
        .mockRejectedValueOnce(new Error('ECONNREFUSED'))
        .mockResolvedValue('success');

      await service.executeWithRetry(operation, {
        operationName: 'test-operation',
        retryConfig: {
          maxRetries: 3,
          initialDelay: 10,
          maxDelay: 100,
          backoffMultiplier: 2,
          jitterFactor: 0,
        },
        onRetry,
      });

      expect(onRetry).toHaveBeenCalledTimes(1);
      expect(onRetry).toHaveBeenCalledWith(
        expect.any(Error),
        expect.any(Number),
        expect.any(Number)
      );
    });

    it('should respect custom shouldRetry function', async () => {
      const operation = vi.fn().mockRejectedValue(new Error('Custom error'));
      const shouldRetry = vi.fn().mockReturnValue(false);

      await expect(
        service.executeWithRetry(operation, {
          operationName: 'test-operation',
          shouldRetry,
        })
      ).rejects.toThrow('Custom error');

      expect(operation).toHaveBeenCalledTimes(1);
      expect(shouldRetry).toHaveBeenCalledTimes(1);
    });
  });

  describe('Circuit Breaker', () => {
    it('should allow requests when circuit is closed', async () => {
      const operation = vi.fn().mockResolvedValue('success');

      const result = await service.executeWithCircuitBreaker(operation, {
        breakerName: 'test-breaker',
      });

      expect(result).toBe('success');
      expect(operation).toHaveBeenCalledTimes(1);
    });

    it('should open circuit after threshold failures', async () => {
      const operation = vi.fn().mockRejectedValue(new Error('Service error'));

      // Fail multiple times to open circuit
      for (let i = 0; i < 5; i++) {
        await expect(
          service.executeWithCircuitBreaker(operation, {
            breakerName: 'test-breaker-2',
            circuitBreakerConfig: {
              failureThreshold: 5,
              successThreshold: 2,
              timeout: 1000,
              monitoringPeriod: 5000,
            },
          })
        ).rejects.toThrow();
      }

      const breaker = service.getCircuitBreaker('test-breaker-2');
      expect(breaker?.getState()).toBe(CircuitState.OPEN);
    });

    it('should reject requests when circuit is open', async () => {
      const operation = vi.fn().mockRejectedValue(new Error('Service error'));

      // Open the circuit
      for (let i = 0; i < 5; i++) {
        await expect(
          service.executeWithCircuitBreaker(operation, {
            breakerName: 'test-breaker-3',
            circuitBreakerConfig: {
              failureThreshold: 5,
              successThreshold: 2,
              timeout: 10000,
              monitoringPeriod: 20000,
            },
          })
        ).rejects.toThrow();
      }

      // Next request should be rejected immediately
      await expect(
        service.executeWithCircuitBreaker(operation, {
          breakerName: 'test-breaker-3',
        })
      ).rejects.toThrow('Circuit breaker');
    });

    it('should use fallback when circuit is open', async () => {
      const operation = vi.fn().mockRejectedValue(new Error('Service error'));
      const fallback = vi.fn().mockResolvedValue('fallback-result');

      // Open the circuit
      for (let i = 0; i < 5; i++) {
        await expect(
          service.executeWithCircuitBreaker(operation, {
            breakerName: 'test-breaker-4',
            circuitBreakerConfig: {
              failureThreshold: 5,
              successThreshold: 2,
              timeout: 10000,
              monitoringPeriod: 20000,
            },
          })
        ).rejects.toThrow();
      }

      // Use fallback
      const result = await service.executeWithCircuitBreaker(operation, {
        breakerName: 'test-breaker-4',
        fallback,
      });

      expect(result).toBe('fallback-result');
      expect(fallback).toHaveBeenCalledTimes(1);
    });

    it('should transition to half-open after timeout', async () => {
      const operation = vi.fn().mockRejectedValue(new Error('Service error'));

      // Open the circuit
      for (let i = 0; i < 5; i++) {
        await expect(
          service.executeWithCircuitBreaker(operation, {
            breakerName: 'test-breaker-5',
            circuitBreakerConfig: {
              failureThreshold: 5,
              successThreshold: 2,
              timeout: 100, // Short timeout for testing
              monitoringPeriod: 5000,
            },
          })
        ).rejects.toThrow();
      }

      // Wait for timeout
      await new Promise(resolve => setTimeout(resolve, 150));

      // Next request should be allowed (half-open)
      operation.mockResolvedValue('success');
      const result = await service.executeWithCircuitBreaker(operation, {
        breakerName: 'test-breaker-5',
      });

      expect(result).toBe('success');
    });

    it('should close circuit after success threshold in half-open', async () => {
      const operation = vi.fn().mockRejectedValue(new Error('Service error'));

      // Open the circuit
      for (let i = 0; i < 5; i++) {
        await expect(
          service.executeWithCircuitBreaker(operation, {
            breakerName: 'test-breaker-6',
            circuitBreakerConfig: {
              failureThreshold: 5,
              successThreshold: 2,
              timeout: 100,
              monitoringPeriod: 5000,
            },
          })
        ).rejects.toThrow();
      }

      // Wait for timeout
      await new Promise(resolve => setTimeout(resolve, 150));

      // Succeed multiple times to close circuit
      operation.mockResolvedValue('success');
      await service.executeWithCircuitBreaker(operation, {
        breakerName: 'test-breaker-6',
      });
      await service.executeWithCircuitBreaker(operation, {
        breakerName: 'test-breaker-6',
      });

      const breaker = service.getCircuitBreaker('test-breaker-6');
      expect(breaker?.getState()).toBe(CircuitState.CLOSED);
    });

    it('should reset circuit breaker', async () => {
      const operation = vi.fn().mockRejectedValue(new Error('Service error'));

      // Open the circuit
      for (let i = 0; i < 5; i++) {
        await expect(
          service.executeWithCircuitBreaker(operation, {
            breakerName: 'test-breaker-7',
            circuitBreakerConfig: {
              failureThreshold: 5,
              successThreshold: 2,
              timeout: 10000,
              monitoringPeriod: 20000,
            },
          })
        ).rejects.toThrow();
      }

      // Reset
      service.resetCircuitBreaker('test-breaker-7');

      const breaker = service.getCircuitBreaker('test-breaker-7');
      expect(breaker?.getState()).toBe(CircuitState.CLOSED);
    });
  });

  describe('Combined Recovery', () => {
    it('should execute with both retry and circuit breaker', async () => {
      const operation = vi
        .fn()
        .mockRejectedValueOnce(new Error('ECONNREFUSED'))
        .mockResolvedValue('success');

      const result = await service.executeWithRecovery(operation, {
        operationName: 'test-operation',
        breakerName: 'test-breaker-combined',
        retryConfig: {
          maxRetries: 3,
          initialDelay: 10,
          maxDelay: 100,
          backoffMultiplier: 2,
          jitterFactor: 0,
        },
      });

      expect(result).toBe('success');
      expect(operation).toHaveBeenCalledTimes(2);
    });

    it('should track circuit breaker failures across retries', async () => {
      const operation = vi.fn().mockRejectedValue(new Error('Service error'));

      // Multiple operations that fail
      for (let i = 0; i < 3; i++) {
        await expect(
          service.executeWithRecovery(operation, {
            operationName: 'test-operation',
            breakerName: 'test-breaker-combined-2',
            retryConfig: {
              maxRetries: 1,
              initialDelay: 10,
              maxDelay: 100,
              backoffMultiplier: 2,
              jitterFactor: 0,
            },
            circuitBreakerConfig: {
              failureThreshold: 3,
              successThreshold: 2,
              timeout: 10000,
              monitoringPeriod: 20000,
            },
          })
        ).rejects.toThrow();
      }

      const breaker = service.getCircuitBreaker('test-breaker-combined-2');
      expect(breaker?.getState()).toBe(CircuitState.OPEN);
    });
  });

  describe('Utility Methods', () => {
    it('should check if error is retryable', () => {
      const retryableError = new Error('ECONNREFUSED');
      const permanentError = {
        code: ErrorCode.VALIDATION_ERROR,
        statusCode: 400,
      };

      expect(service.isRetryable(retryableError)).toBe(true);
      expect(service.isRetryable(permanentError)).toBe(false);
    });

    it('should get suggested delay for error', () => {
      const rateLimitError = { statusCode: 429 };
      const networkError = new Error('ECONNREFUSED');

      const rateLimitDelay = service.getSuggestedDelay(rateLimitError);
      const networkDelay = service.getSuggestedDelay(networkError);

      expect(rateLimitDelay).toBeGreaterThan(networkDelay);
    });

    it('should get max retries for error', () => {
      const retryableError = new Error('ECONNREFUSED');
      const permanentError = {
        code: ErrorCode.VALIDATION_ERROR,
        statusCode: 400,
      };

      expect(service.getMaxRetries(retryableError)).toBeGreaterThan(0);
      expect(service.getMaxRetries(permanentError)).toBe(0);
    });

    it('should get all circuit breaker stats', async () => {
      const operation = vi.fn().mockResolvedValue('success');

      await service.executeWithCircuitBreaker(operation, {
        breakerName: 'breaker-1',
      });
      await service.executeWithCircuitBreaker(operation, {
        breakerName: 'breaker-2',
      });

      const stats = service.getAllCircuitBreakerStats();

      expect(stats['breaker-1']).toBeDefined();
      expect(stats['breaker-2']).toBeDefined();
      expect(stats['breaker-1'].state).toBe(CircuitState.CLOSED);
    });

    it('should reset all circuit breakers', async () => {
      const operation = vi.fn().mockRejectedValue(new Error('Service error'));

      // Create multiple breakers
      for (let i = 0; i < 5; i++) {
        await expect(
          service.executeWithCircuitBreaker(operation, {
            breakerName: 'breaker-reset-1',
            circuitBreakerConfig: {
              failureThreshold: 5,
              successThreshold: 2,
              timeout: 10000,
              monitoringPeriod: 20000,
            },
          })
        ).rejects.toThrow();
      }

      service.resetAllCircuitBreakers();

      const breaker = service.getCircuitBreaker('breaker-reset-1');
      expect(breaker?.getState()).toBe(CircuitState.CLOSED);
    });
  });
});

