describe('Error Recovery Integration', () => {
  beforeEach(() => {
    service = new ScraperQueueService(3);
    vi.clearAllMocks();
  });

  describe('executeJobWithRecovery', () => {
    it('should execute job successfully on first attempt', async () => {
      const job = service.enqueueJob('source-1');
      const operation = vi.fn().mockResolvedValue({ data: 'success' });

      const result = await service.executeJobWithRecovery(job.id, operation);

      expect(result).toEqual({ data: 'success' });
      expect(operation).toHaveBeenCalledTimes(1);

      const completedJob = service.getJobStatus(job.id);
      expect(completedJob?.status).toBe('SUCCESS');
    });

    it('should retry on transient errors', async () => {
      const job = service.enqueueJob('source-1', { maxRetries: 3 });
      const operation = vi
        .fn()
        .mockRejectedValueOnce(new Error('ECONNREFUSED'))
        .mockResolvedValue({ data: 'success' });

      const result = await service.executeJobWithRecovery(job.id, operation);

      expect(result).toEqual({ data: 'success' });
      expect(operation).toHaveBeenCalledTimes(2);

      const completedJob = service.getJobStatus(job.id);
      expect(completedJob?.status).toBe('SUCCESS');
    });

    it('should not retry on permanent errors', async () => {
      const job = service.enqueueJob('source-1', { maxRetries: 3 });
      const error = {
        code: 'ERR_1005',
        statusCode: 400,
        message: 'Validation error',
      };
      const operation = vi.fn().mockRejectedValue(error);

      await expect(
        service.executeJobWithRecovery(job.id, operation)
      ).rejects.toEqual(error);

      expect(operation).toHaveBeenCalledTimes(1);

      const failedJob = service.getJobStatus(job.id);
      expect(failedJob?.status).toBe('FAILED');
    });

    it('should fail after max retries exhausted', async () => {
      const job = service.enqueueJob('source-1', { maxRetries: 2 });
      const error = new Error('ECONNREFUSED');
      const operation = vi.fn().mockRejectedValue(error);

      await expect(
        service.executeJobWithRecovery(job.id, operation)
      ).rejects.toThrow('ECONNREFUSED');

      expect(operation).toHaveBeenCalledTimes(3); // Initial + 2 retries

      const failedJob = service.getJobStatus(job.id);
      expect(failedJob?.status).toBe('FAILED');
    });

    it('should handle timeout errors with retry', async () => {
      const job = service.enqueueJob('source-1', { maxRetries: 3 });
      const operation = vi
        .fn()
        .mockRejectedValueOnce(new Error('Request timeout'))
        .mockResolvedValue({ data: 'success' });

      const result = await service.executeJobWithRecovery(job.id, operation);

      expect(result).toEqual({ data: 'success' });
      expect(operation).toHaveBeenCalledTimes(2);
    });

    it('should handle rate limit errors with longer delay', async () => {
      const job = service.enqueueJob('source-1', { maxRetries: 3 });
      const error = {
        message: 'Too many requests',
        statusCode: 429,
      };
      const operation = vi
        .fn()
        .mockRejectedValueOnce(error)
        .mockResolvedValue({ data: 'success' });

      const result = await service.executeJobWithRecovery(job.id, operation);

      expect(result).toEqual({ data: 'success' });
      expect(operation).toHaveBeenCalledTimes(2);
    });

    it('should throw error for non-existent job', async () => {
      const operation = vi.fn().mockResolvedValue({ data: 'success' });

      await expect(
        service.executeJobWithRecovery('non-existent', operation)
      ).rejects.toThrow('Job tidak ditemukan');
    });
  });

  describe('Circuit Breaker Integration', () => {
    it('should get circuit breaker stats for source', () => {
      const stats = service.getCircuitBreakerStats('source-1');

      // Initially null (breaker not created yet)
      expect(stats).toBeNull();
    });

    it('should reset circuit breaker for source', () => {
      expect(() => {
        service.resetCircuitBreaker('source-1');
      }).not.toThrow();
    });

    it('should track failures across multiple jobs for same source', async () => {
      const error = new Error('Service error');

      // Create multiple jobs for same source that fail
      for (let i = 0; i < 3; i++) {
        const job = service.enqueueJob('source-1', { maxRetries: 0 });
        const operation = vi.fn().mockRejectedValue(error);

        await expect(
          service.executeJobWithRecovery(job.id, operation)
        ).rejects.toThrow();
      }

      // Circuit breaker should have recorded failures
      const stats = service.getCircuitBreakerStats('source-1');
      expect(stats).toBeDefined();
      expect(stats.failureCount).toBeGreaterThan(0);
    });
  });

  describe('Error Classification in failJob', () => {
    it('should classify network errors as retryable', () => {
      const job = service.enqueueJob('source-1', { maxRetries: 3 });
      service.dequeueJob();

      const error = new Error('ECONNREFUSED');
      const failedJob = service.failJob(job.id, error.message, error);

      expect(failedJob.status).toBe('PENDING'); // Should retry
      expect(failedJob.retryCount).toBe(1);
    });

    it('should classify validation errors as non-retryable', () => {
      const job = service.enqueueJob('source-1', { maxRetries: 3 });
      service.dequeueJob();

      const error = {
        code: 'ERR_1005',
        statusCode: 400,
        message: 'Validation error',
      };
      const failedJob = service.failJob(job.id, error.message, error);

      expect(failedJob.status).toBe('FAILED'); // Should not retry
      expect(failedJob.retryCount).toBe(1);
    });

    it('should classify 404 errors as non-retryable', () => {
      const job = service.enqueueJob('source-1', { maxRetries: 3 });
      service.dequeueJob();

      const error = {
        statusCode: 404,
        message: 'Not found',
      };
      const failedJob = service.failJob(job.id, error.message, error);

      expect(failedJob.status).toBe('FAILED'); // Should not retry
    });

    it('should classify 500 errors as retryable', () => {
      const job = service.enqueueJob('source-1', { maxRetries: 3 });
      service.dequeueJob();

      const error = {
        statusCode: 500,
        message: 'Internal server error',
      };
      const failedJob = service.failJob(job.id, error.message, error);

      expect(failedJob.status).toBe('PENDING'); // Should retry
      expect(failedJob.retryCount).toBe(1);
    });

    it('should respect max retries even for retryable errors', () => {
      const job = service.enqueueJob('source-1', { maxRetries: 1 });
      service.dequeueJob();

      const error = new Error('ECONNREFUSED');
      const failedJob = service.failJob(job.id, error.message, error);

      expect(failedJob.status).toBe('FAILED'); // Max retries reached
      expect(failedJob.retryCount).toBe(1);
    });
  });

  describe('Progress Updates During Retry', () => {
    it('should update progress during retry attempts', async () => {
      const job = service.enqueueJob('source-1', { maxRetries: 2 });
      let retryCount = 0;

      const operation = vi.fn().mockImplementation(() => {
        retryCount++;
        if (retryCount < 2) {
          return Promise.reject(new Error('ECONNREFUSED'));
        }
        return Promise.resolve({ data: 'success' });
      });

      const result = await service.executeJobWithRecovery(job.id, operation);

      expect(result).toEqual({ data: 'success' });
      expect(retryCount).toBe(2);
    });
  });
});
